-- Create a read-only analytics role
CREATE ROLE analyst_readonly;
GRANT CONNECT ON DATABASE production TO analyst_readonly;
GRANT USAGE ON SCHEMA public TO analyst_readonly;
GRANT SELECT ON ALL TABLES IN SCHEMA public TO analyst_readonly;

-- The intern gets THIS role. Not superuser.
GRANT analyst_readonly TO summer_intern;

-- Enable RLS on the table
ALTER TABLE customer_data ENABLE ROW LEVEL SECURITY;

-- Policy: users can only see their own company's data
CREATE POLICY company_isolation ON customer_data
  USING (company_id = current_setting('app.company_id')::int);

-- Set the context per-connection (in your app middleware):
SET app.company_id = 42;

-- Now ALL queries on this table are automatically filtered.
-- Even SELECT * FROM customer_data only returns company 42.
-- Even if a developer forgets the WHERE clause.

-- Test data:
-- {"theme": "dark", "notifications": true}

-- Production data (from a different API):
-- {"theme": "dark", "notifications": "true"}

SELECT * FROM users
WHERE preferences @> '{"notifications": true}'::jsonb;

-- Hard delete: simple, permanent
DELETE FROM users WHERE id = 42;

-- Soft delete: reversible, haunted
UPDATE users SET deleted_at = NOW() WHERE id = 42;

-- Every query must now exorcise the ghosts:
SELECT * FROM users WHERE deleted_at IS NULL;

-- Or use a view to hide the complexity:
CREATE VIEW active_users AS
SELECT * FROM users WHERE deleted_at IS NULL;

-- Or (PostgreSQL) use a partial index:
CREATE INDEX idx_active_users ON users (email)
WHERE deleted_at IS NULL;

