BEGIN;
  UPDATE inventory SET stock = stock - 1 WHERE product_id = 99;
  SAVEPOINT after_inventory;
  INSERT INTO audit_log (action) VALUES ('sold');
  -- If audit fails, roll back just the audit:
  ROLLBACK TO after_inventory;
  -- Inventory change is preserved.
COMMIT;

